import { createAuthPlugin } from "@better-auth-ui/core"
import {
  type ThemePluginOptions as CoreThemePluginOptions,
  themePlugin as coreThemePlugin,
  type ThemeLocalization
} from "@better-auth-ui/core/plugins/theme"
import { Appearance } from "@/components/auth/theme/appearance"
import { ThemeToggleItem } from "@/components/auth/theme/theme-toggle-item"
import { applyThemePreference, isThemeMode } from "@/lib/theme"

export type ThemePluginOptions = Partial<
  Pick<CoreThemePluginOptions, "localization" | "theme" | "themes">
> & {
  /** Function to set the theme. Defaults to the copied Solid theme helper. */
  setTheme?: CoreThemePluginOptions["setTheme"]
}

export type { ThemeLocalization }

const setLocalTheme = (theme: string) => {
  if (isThemeMode(theme)) applyThemePreference(theme)
}

export const themePlugin = createAuthPlugin(
  coreThemePlugin.id,
  (options: ThemePluginOptions = {}) => {
    const core = coreThemePlugin({
      localization: options.localization,
      setTheme: options.setTheme ?? setLocalTheme,
      theme: options.theme,
      themes: options.themes
    })

    return {
      ...core,
      theme: options.theme,
      accountCards: [Appearance],
      userMenuItems: [ThemeToggleItem]
    }
  }
)

import { useAuth } from "@better-auth-ui/solid"
import { Monitor, Moon, PaletteIcon, Sun } from "lucide-solid"
import { createSignal, For, onMount } from "solid-js"
import {
  resolveThemePluginState,
  type ThemeOption
} from "@/components/auth/theme/theme-plugin-state"
import { DropdownMenuItem } from "@/components/ui/dropdown-menu"
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { applyThemePreference, isThemeMode, type ThemeMode } from "@/lib/theme"
import { cn } from "@/lib/utils"

export type ThemeToggleItemProps = {
  class?: string
}

const themeIcon = (value: ThemeMode) => {
  if (value === "light") return Sun
  if (value === "dark") return Moon

  return Monitor
}

const themeLabel = (
  localization: ReturnType<typeof resolveThemePluginState>["localization"],
  option: ThemeOption
) => localization[option.value]

export function ThemeToggleItem(props: ThemeToggleItemProps = {}) {
  const auth = useAuth()
  const themeState = () => resolveThemePluginState(auth.plugins)
  const [theme, setTheme] = createSignal<ThemeMode>(themeState().theme)
  let tabsListElement!: HTMLDivElement

  onMount(() => {
    const initialTheme = themeState().theme

    setTheme(initialTheme)
    applyThemePreference(initialTheme)
  })

  const selectTheme = (nextTheme: ThemeMode) => {
    setTheme(nextTheme)
    themeState().setTheme(nextTheme)
  }

  const focusActiveTab = () => {
    const activeTab = tabsListElement?.querySelector<HTMLElement>(
      '[role="tab"][data-selected]'
    )

    activeTab?.focus({ preventScroll: true })
  }

  const handleTabsKeyDown = (event: KeyboardEvent) => {
    if (event.key !== "ArrowUp" && event.key !== "ArrowDown") return

    const target = event.target as HTMLElement
    if (target.getAttribute("role") !== "tab") return

    const wrapper = target.closest<HTMLElement>('[role="menuitem"]')
    const content = wrapper?.closest<HTMLElement>(
      '[data-slot="dropdown-menu-content"]'
    )
    if (!wrapper || !content) return

    const items = Array.from(
      content.querySelectorAll<HTMLElement>(
        '[role="menuitem"]:not([aria-disabled="true"])'
      )
    )
    const currentIndex = items.indexOf(wrapper)
    const nextIndex =
      event.key === "ArrowDown" ? currentIndex + 1 : currentIndex - 1
    const next = items[nextIndex]
    if (!next) return

    event.preventDefault()
    next.focus()
  }

  return (
    <DropdownMenuItem
      class={cn(
        "z-dropdown-menu-item-auth hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground data-expanded:bg-accent data-expanded:text-accent-foreground",
        props.class
      )}
      closeOnSelect={false}
      onFocus={(event) => {
        if (event.target === event.currentTarget) focusActiveTab()
      }}
    >
      <div class="flex w-full items-center gap-2">
        <PaletteIcon class="size-4 text-muted-foreground" />
        <span>{themeState().localization.theme}</span>

        <Tabs
          class="ml-auto"
          onKeyDown={handleTabsKeyDown}
          onChange={(nextTheme) => {
            if (isThemeMode(nextTheme)) selectTheme(nextTheme)
          }}
          value={theme()}
        >
          <TabsList class="z-tabs-list-theme-toggle" ref={tabsListElement}>
            <For each={themeState().themes}>
              {(option) => {
                const Icon = themeIcon(option.value)

                return (
                  <TabsTrigger
                    aria-label={themeLabel(themeState().localization, option)}
                    class="size-5 p-0"
                    value={option.value}
                  >
                    <Icon class="size-3" />
                  </TabsTrigger>
                )
              }}
            </For>
          </TabsList>
        </Tabs>
      </div>
    </DropdownMenuItem>
  )
}

import { themeLocalization, themePlugin } from "@better-auth-ui/core/plugins/theme"
import {
  applyThemePreference,
  isThemeMode,
  readStoredThemePreference,
  saveThemePreference,
  type ThemeMode
} from "@/lib/theme"

type ThemePluginState = {
  id: string
  localization?: Partial<typeof themeLocalization>
  setTheme?: (theme: string) => void
  theme?: string
  themes?: string[]
}

export type ThemeOption = {
  value: ThemeMode
}

export const themeOptions = [
  { value: "system" },
  { value: "light" },
  { value: "dark" }
] as const satisfies readonly ThemeOption[]

const readInitialThemePreference = () => {
  if (typeof window === "undefined") return "system"

  return readStoredThemePreference()
}

export const resolveThemePluginState = (plugins: ThemePluginState[]) => {
  const plugin = plugins.find((candidate) => candidate.id === themePlugin.id)
  const allowedThemes = new Set(
    plugin?.themes ?? themeOptions.map((option) => option.value)
  )
  const themes = themeOptions.filter((option) =>
    allowedThemes.has(option.value)
  )
  const configuredTheme = plugin?.theme ?? null
  const initialTheme = isThemeMode(configuredTheme)
    ? configuredTheme
    : readInitialThemePreference()
  const setTheme = plugin?.setTheme ?? applyThemePreference

  return {
    localization: {
      ...themeLocalization,
      ...plugin?.localization
    },
    setTheme: (theme: ThemeMode) => {
      saveThemePreference(theme)
      setTheme(theme)
    },
    theme: themes.some((option) => option.value === initialTheme)
      ? initialTheme
      : (themes[0]?.value ?? "system"),
    themes
  }
}

export type ThemeMode = "system" | "light" | "dark"

export const themeStorageKey = "start-solid-zaidan-theme"

export const isThemeMode = (value: string | null): value is ThemeMode =>
  value === "system" || value === "light" || value === "dark"

export const resolveThemePreference = (
  theme: ThemeMode,
  prefersDark: boolean
): "light" | "dark" =>
  theme === "system" ? (prefersDark ? "dark" : "light") : theme

export const setDocumentThemeClass = (theme: "light" | "dark") => {
  document.documentElement.classList.remove("light", "dark")
  document.documentElement.classList.add(theme)
}

export const readStoredThemePreference = (): ThemeMode => {
  const storedTheme = localStorage.getItem(themeStorageKey)

  return isThemeMode(storedTheme) ? storedTheme : "system"
}

export const saveThemePreference = (theme: ThemeMode) => {
  localStorage.setItem(themeStorageKey, theme)
}

export const applyThemePreference = (theme: ThemeMode) => {
  const prefersDark = matchMedia("(prefers-color-scheme: dark)").matches

  setDocumentThemeClass(resolveThemePreference(theme, prefersDark))
}

export const syncDocumentThemePreference = () => {
  const mediaQuery = matchMedia("(prefers-color-scheme: dark)")
  const applyStoredPreference = () => {
    applyThemePreference(readStoredThemePreference())
  }
  const handleSystemThemeChange = () => {
    if (readStoredThemePreference() === "system") applyStoredPreference()
  }
  const handleStorage = (event: StorageEvent) => {
    if (event.key === themeStorageKey) applyStoredPreference()
  }

  applyStoredPreference()
  window.addEventListener("storage", handleStorage)
  mediaQuery.addEventListener("change", handleSystemThemeChange)

  return () => {
    window.removeEventListener("storage", handleStorage)
    mediaQuery.removeEventListener("change", handleSystemThemeChange)
  }
}

export const themeScript = `
try {
  const themeStorageKey = "${themeStorageKey}";
  const storedTheme = localStorage.getItem(themeStorageKey);
  const theme = storedTheme === "light" || storedTheme === "dark" || storedTheme === "system" ? storedTheme : "system";
  const prefersDark = matchMedia("(prefers-color-scheme: dark)").matches;
  const resolvedTheme = theme === "system" ? (prefersDark ? "dark" : "light") : theme;
  document.documentElement.classList.remove("light", "dark");
  document.documentElement.classList.add(resolvedTheme);
} catch (_) {}
`

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
